import React, { useState } from 'react';
import { Button } from './Button';
import { FormStatus, LeadFormData } from '../types';
import { Send, CheckCircle } from 'lucide-react';

export const LeadForm: React.FC = () => {
  const [formData, setFormData] = useState<LeadFormData>({
    name: '',
    phone: '',
    productName: '',
    budget: ''
  });
  const [status, setStatus] = useState<FormStatus>(FormStatus.IDLE);

  const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement | HTMLSelectElement>) => {
    const { name, value } = e.target;
    setFormData(prev => ({ ...prev, [name]: value }));
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    setStatus(FormStatus.SUBMITTING);

    // Simulate API Call
    setTimeout(() => {
      setStatus(FormStatus.SUCCESS);
      console.log('Form submitted:', formData);
    }, 1500);
  };

  if (status === FormStatus.SUCCESS) {
    return (
      <section id="lead-form" className="py-20 px-4 bg-navy-900 text-white flex justify-center">
        <div className="max-w-lg w-full bg-navy-800 p-8 rounded-2xl shadow-2xl text-center border border-slate-700">
          <CheckCircle className="w-20 h-20 text-green-500 mx-auto mb-6" />
          <h3 className="text-3xl font-bold mb-4">تم استلام طلبك بنجاح!</h3>
          <p className="text-xl text-slate-300">
            شكراً لك {formData.name}. سيتواصل معك أحد خبراء الاستيراد لدينا عبر الواتساب قريباً جداً لمناقشة التفاصيل.
          </p>
        </div>
      </section>
    );
  }

  return (
    <section id="lead-form" className="py-20 px-4 bg-navy-900 text-white">
      <div className="max-w-2xl mx-auto">
        <div className="text-center mb-10">
          <h2 className="text-3xl md:text-5xl font-bold mb-4">ابدأ طلبك المجاني الآن</h2>
          <p className="text-slate-300 text-lg">املأ النموذج أدناه ولنبدأ العمل على مشروعك.</p>
        </div>

        <form onSubmit={handleSubmit} className="bg-white text-slate-900 p-6 md:p-10 rounded-2xl shadow-2xl">
          <div className="space-y-6">
            <div>
              <label htmlFor="name" className="block text-sm font-bold mb-2 text-navy-900">الاسم الكامل</label>
              <input
                type="text"
                id="name"
                name="name"
                required
                className="w-full p-4 bg-slate-50 border border-slate-300 rounded-lg focus:ring-2 focus:ring-brand-orange focus:border-transparent outline-none transition"
                placeholder="محمد بن فلان"
                value={formData.name}
                onChange={handleChange}
              />
            </div>

            <div>
              <label htmlFor="phone" className="block text-sm font-bold mb-2 text-navy-900">رقم الهاتف (واتساب)</label>
              <input
                type="tel"
                id="phone"
                name="phone"
                required
                className="w-full p-4 bg-slate-50 border border-slate-300 rounded-lg focus:ring-2 focus:ring-brand-orange focus:border-transparent outline-none transition"
                placeholder="0770 XX XX XX"
                value={formData.phone}
                onChange={handleChange}
              />
            </div>

            <div>
              <label htmlFor="productName" className="block text-sm font-bold mb-2 text-navy-900">اسم المنتج أو الرابط (علي بابا)</label>
              <input
                type="text"
                id="productName"
                name="productName"
                required
                className="w-full p-4 bg-slate-50 border border-slate-300 rounded-lg focus:ring-2 focus:ring-brand-orange focus:border-transparent outline-none transition"
                placeholder="مثال: سماعات بلوتوث، آلات تغليف..."
                value={formData.productName}
                onChange={handleChange}
              />
            </div>

            <div>
              <label htmlFor="budget" className="block text-sm font-bold mb-2 text-navy-900">الميزانية التقريبية (دج)</label>
              <select
                id="budget"
                name="budget"
                required
                className="w-full p-4 bg-slate-50 border border-slate-300 rounded-lg focus:ring-2 focus:ring-brand-orange focus:border-transparent outline-none transition"
                value={formData.budget}
                onChange={handleChange}
              >
                <option value="" disabled>اختر الميزانية</option>
                <option value="100k-500k">10 - 50 مليون سنتيم</option>
                <option value="500k-2m">50 - 200 مليون سنتيم</option>
                <option value="2m+">أكثر من 200 مليون سنتيم</option>
              </select>
            </div>

            <Button type="submit" fullWidth disabled={status === FormStatus.SUBMITTING}>
              {status === FormStatus.SUBMITTING ? 'جاري الإرسال...' : 'أرسل طلب المصادر المجاني'}
              {!status && <Send className="w-5 h-5 mr-2" />}
            </Button>

            <p className="text-xs text-center text-slate-500 mt-4">
              نحترم خصوصيتك. بياناتك آمنة 100% ولن يتم مشاركتها.
            </p>
          </div>
        </form>
      </div>
    </section>
  );
};

