import React, { useState } from 'react';
import { ChevronDown, ChevronUp, HelpCircle } from 'lucide-react';

interface FAQItemProps {
  question: string;
  answer: string;
}

const FAQItem: React.FC<FAQItemProps> = ({ question, answer }) => {
  const [isOpen, setIsOpen] = useState(false);

  return (
    <div className="border border-slate-200 rounded-lg bg-white overflow-hidden mb-4 shadow-sm">
      <button
        onClick={() => setIsOpen(!isOpen)}
        className="w-full flex items-center justify-between p-4 md:p-6 text-right focus:outline-none hover:bg-slate-50 transition-colors"
      >
        <div className="flex items-center gap-3">
          <HelpCircle className="w-6 h-6 text-brand-orange flex-shrink-0" />
          <span className="font-bold text-lg text-navy-900">{question}</span>
        </div>
        {isOpen ? (
          <ChevronUp className="w-5 h-5 text-slate-400" />
        ) : (
          <ChevronDown className="w-5 h-5 text-slate-400" />
        )}
      </button>

      {isOpen && (
        <div className="p-4 md:p-6 bg-slate-50 border-t border-slate-100 text-slate-700 leading-relaxed animate-fadeIn">
          {answer}
        </div>
      )}
    </div>
  );
};

