import React from 'react';

interface ButtonProps {
  children: React.ReactNode;
  onClick?: () => void;
  fullWidth?: boolean;
  className?: string;
  type?: 'button' | 'submit' | 'reset';
  disabled?: boolean;
  href?: string;
  variant?: 'orange' | 'blue';
}

export const Button: React.FC<ButtonProps> = ({ 
  children, 
  onClick, 
  fullWidth = false, 
  className = '',
  type = 'button',
  disabled = false,
  href,
  variant = 'orange'
}) => {
  const colorClasses = variant === 'blue' 
    ? 'bg-blue-600 hover:bg-blue-700 shadow-blue-900/20' 
    : 'bg-brand-orange hover:bg-brand-orangeHover shadow-orange-900/20';

  const baseClasses = `
    ${colorClasses} text-white font-bold py-4 px-8 rounded-lg shadow-lg 
    transition-transform transform hover:-translate-y-1 active:translate-y-0
    text-lg md:text-xl flex items-center justify-center gap-2
    ${fullWidth ? 'w-full' : ''}
    ${disabled ? 'opacity-70 cursor-not-allowed transform-none' : ''}
    ${className}
  `;

  if (href) {
    return (
      <a href={href} className={baseClasses}>
        {children}
      </a>
    );
  }

  return (
    <button
      type={type}
      onClick={onClick}
      disabled={disabled}
      className={baseClasses}
    >
      {children}
    </button>
  );
};

