import React from 'react';

interface ButtonProps {
  children: React.ReactNode;
  onClick?: () => void;
  fullWidth?: boolean;
  className?: string;
  type?: 'button' | 'submit' | 'reset';
  disabled?: boolean;
  href?: string;
  variant?: 'orange' | 'blue';
}

export const Button: React.FC<ButtonProps> = ({ 
  children, 
  onClick, 
  fullWidth = false, 
  className = '',
  type = 'button',
  disabled = false,
  href,
  variant = 'orange'
}) => {
  // Orange variant is now mapped to Cyan in Tailwind config.
  // Blue variant needs to be Dark Navy to contrast with Cyan.
  const colorClasses = variant === 'blue' 
    ? 'bg-slate-800 hover:bg-slate-700 shadow-slate-900/20' 
    : 'bg-brand-orange hover:bg-brand-orangeHover shadow-cyan-900/20';

  const baseClasses = `
    ${colorClasses} text-white font-bold py-4 px-8 rounded-lg shadow-lg 
    transition-transform transform hover:-translate-y-1 active:translate-y-0
    text-lg md:text-xl flex items-center justify-center gap-2
    ${fullWidth ? 'w-full' : ''}
    ${disabled ? 'opacity-70 cursor-not-allowed transform-none' : ''}
    ${className}
  `;

  if (href) {
    return (
      <a href={href} className={baseClasses}>
        {children}
      </a>
    );
  }

  return (
    <button
      type={type}
      onClick={onClick}
      disabled={disabled}
      className={baseClasses}
    >
      {children}
    </button>
  );
};

